// dropos-phase1.js — node dropos-phase1.js
const fs=require('fs'),path=require('path'),{execSync}=require('child_process');
const files={"frontend/src/components/kai/KAIChat.tsx":"\"use client\";\nimport { useState, useRef, useEffect, useCallback } from \"react\";\nimport { motion, AnimatePresence }                  from \"framer-motion\";\nimport { useAuthStore }                             from \"../../../store/auth.store\";\nimport { api }                                      from \"../../../lib/api\";\nimport {\n  Send, Sparkles, Copy, Check, ThumbsUp, RotateCcw,\n  Loader2, Plus, X, Zap, BarChart2, ShoppingCart,\n  Package, TrendingUp, Image, Paperclip, Mic,\n} from \"lucide-react\";\nimport toast from \"react-hot-toast\";\n\ninterface Message {\n  id:          string;\n  role:        \"user\" | \"KIRO\";\n  content:     string;\n  timestamp:   Date;\n  isStreaming?: boolean;\n  actions?:    Array<{ label: string; action: string; payload?: any }>;\n  dataCard?:   any;\n  type?:       \"text\" | \"action_result\" | \"error\";\n}\n\nconst QUICK_CHIPS = [\n  { icon: \"📊\", label: \"Sales today\",           prompt: \"What are my sales today?\" },\n  { icon: \"📦\", label: \"Unfulfilled orders\",     prompt: \"Show me orders that need fulfillment\" },\n  { icon: \"🔥\", label: \"Trending products\",      prompt: \"What products are trending right now in Nigeria?\" },\n  { icon: \"✍️\",  label: \"TikTok script\",          prompt: \"Write a TikTok script for my best-selling product\" },\n  { icon: \"💰\", label: \"Protect margins\",        prompt: \"Alert me if any product margin drops below 30%\" },\n  { icon: \"📈\", label: \"Revenue forecast\",       prompt: \"Forecast my revenue for the next 30 days\" },\n  { icon: \"🎯\", label: \"Improve store score\",   prompt: \"How can I improve my store health score?\" },\n  { icon: \"🔍\", label: \"Find better supplier\",   prompt: \"Find me a better supplier for my top products\" },\n];\n\nfunction KIROAvatar({ size = 32 }: { size?: number }) {\n  return (\n    <div style={{ width: size, height: size, borderRadius: size * 0.3, background: \"linear-gradient(145deg,#6B35E8,#1A0D3D)\", display: \"flex\", alignItems: \"center\", justifyContent: \"center\", flexShrink: 0, boxShadow: \"0 2px 12px rgba(107,53,232,0.4)\" }}>\n      <Zap size={size * 0.45} color=\"white\" />\n    </div>\n  );\n}\n\nfunction TypingIndicator() {\n  return (\n    <div style={{ display: \"flex\", alignItems: \"center\", gap: 4, padding: \"10px 14px\", background: \"rgba(255,255,255,0.04)\", borderRadius: 14, width: \"fit-content\" }}>\n      {[0, 1, 2].map(i => (\n        <motion.div key={i} style={{ width: 5, height: 5, borderRadius: \"50%\", background: \"#8B5CF6\" }}\n          animate={{ scale: [1, 1.4, 1], opacity: [0.4, 1, 0.4] }}\n          transition={{ duration: 0.9, delay: i * 0.18, repeat: Infinity }} />\n      ))}\n    </div>\n  );\n}\n\nfunction ActionButtons({ actions, onAction }: { actions: Array<{ label: string; action: string; payload?: any }>; onAction: (a: any) => void }) {\n  if (!actions?.length) return null;\n  return (\n    <div style={{ display: \"flex\", flexWrap: \"wrap\", gap: 6, marginTop: 10 }}>\n      {actions.map((a, i) => (\n        <button key={i} onClick={() => onAction(a)}\n          style={{ padding: \"6px 14px\", borderRadius: 20, fontSize: 12, fontWeight: 600, cursor: \"pointer\", border: \"1px solid rgba(107,53,232,0.35)\", background: \"rgba(107,53,232,0.1)\", color: \"#A78BFA\", transition: \"all 0.15s\" }}>\n          {a.label}\n        </button>\n      ))}\n    </div>\n  );\n}\n\nfunction MessageBubble({ msg, onAction, onCopy }: { msg: Message; onAction: (a: any) => void; onCopy: (t: string) => void }) {\n  const isKIRO = msg.role === \"KIRO\";\n  const [copied, setCopied] = useState(false);\n\n  const handleCopy = () => {\n    navigator.clipboard.writeText(msg.content);\n    setCopied(true);\n    setTimeout(() => setCopied(false), 2000);\n    onCopy(msg.id);\n  };\n\n  if (isKIRO) {\n    return (\n      <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} style={{ display: \"flex\", gap: 10, alignItems: \"flex-start\", maxWidth: \"100%\" }}>\n        <KIROAvatar size={28} />\n        <div style={{ flex: 1, minWidth: 0 }}>\n          {msg.isStreaming && msg.content === \"\" ? <TypingIndicator /> : (\n            <div>\n              {/* Render markdown-ish content cleanly */}\n              <div style={{ fontSize: 14, lineHeight: 1.7, color: \"rgba(255,255,255,0.88)\", whiteSpace: \"pre-wrap\", wordBreak: \"break-word\" }}>\n                {msg.content.split(\"\\n\").map((line, i) => {\n                  if (line.startsWith(\"## \")) return <p key={i} style={{ fontWeight: 800, fontSize: 15, color: \"#fff\", margin: \"12px 0 4px\" }}>{line.slice(3)}</p>;\n                  if (line.startsWith(\"# \")) return <p key={i} style={{ fontWeight: 900, fontSize: 16, color: \"#fff\", margin: \"14px 0 6px\" }}>{line.slice(2)}</p>;\n                  if (line.startsWith(\"**\") && line.endsWith(\"**\")) return <p key={i} style={{ fontWeight: 700, color: \"#fff\" }}>{line.slice(2, -2)}</p>;\n                  if (line.startsWith(\"- \") || line.startsWith(\"• \")) return <p key={i} style={{ paddingLeft: 16, position: \"relative\", color: \"rgba(255,255,255,0.75)\" }}><span style={{ position: \"absolute\", left: 4, color: \"#8B5CF6\" }}>•</span>{line.slice(2)}</p>;\n                  if (/^\\d+\\./.test(line)) return <p key={i} style={{ paddingLeft: 20, color: \"rgba(255,255,255,0.75)\" }}>{line}</p>;\n                  if (line === \"\") return <br key={i} />;\n                  return <span key={i}>{line}{i < msg.content.split(\"\\n\").length - 1 ? \"\\n\" : \"\"}</span>;\n                })}\n                {msg.isStreaming && <motion.span animate={{ opacity: [0, 1] }} transition={{ duration: 0.5, repeat: Infinity }} style={{ display: \"inline-block\", width: 2, height: 14, background: \"#8B5CF6\", marginLeft: 2, verticalAlign: \"middle\" }} />}\n              </div>\n              {!msg.isStreaming && msg.content && (\n                <button onClick={handleCopy} style={{ marginTop: 6, display: \"flex\", alignItems: \"center\", gap: 4, fontSize: 11, color: \"rgba(255,255,255,0.25)\", background: \"none\", border: \"none\", cursor: \"pointer\", padding: \"2px 0\" }}>\n                  {copied ? <><Check size={10} /> Copied</> : <><Copy size={10} /> Copy</>}\n                </button>\n              )}\n              {!msg.isStreaming && msg.actions && <ActionButtons actions={msg.actions} onAction={onAction} />}\n            </div>\n          )}\n        </div>\n      </motion.div>\n    );\n  }\n\n  return (\n    <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} style={{ display: \"flex\", justifyContent: \"flex-end\" }}>\n      <div style={{ maxWidth: \"75%\", padding: \"10px 14px\", borderRadius: \"18px 18px 4px 18px\", background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\", fontSize: 14, lineHeight: 1.6, color: \"#fff\", wordBreak: \"break-word\" }}>\n        {msg.content}\n      </div>\n    </motion.div>\n  );\n}\n\ninterface KIROChatProps {\n  className?:        string;\n  storeId?:          string;\n  initialMessage?:   string;\n  compact?:          boolean;\n}\n\nexport default function KIROChat({ className, storeId: propStoreId, initialMessage, compact }: KIROChatProps) {\n  const { user }           = useAuthStore();\n  const effectiveStoreId   = propStoreId || user?.stores?.[0]?.id || \"\";\n  const [messages, setMessages] = useState<Message[]>([]);\n  const [input,    setInput]    = useState(initialMessage || \"\");\n  const [loading,  setLoading]  = useState(false);\n  const [sessionId, setSessionId] = useState(\"\");\n  const bottomRef  = useRef<HTMLDivElement>(null);\n  const inputRef   = useRef<HTMLTextAreaElement>(null);\n  const abortRef   = useRef<AbortController | null>(null);\n\n  useEffect(() => {\n    bottomRef.current?.scrollIntoView({ behavior: \"smooth\" });\n  }, [messages]);\n\n  useEffect(() => {\n    if (initialMessage) { setInput(initialMessage); inputRef.current?.focus(); }\n  }, [initialMessage]);\n\n  // ── Execute KIRO action ────────────────────────────────────\n  const executeAction = useCallback(async (action: { action: string; payload?: any; label: string }) => {\n    const confirmMsg: Message = {\n      id: Date.now().toString(), role: \"user\",\n      content: `Execute: ${action.label}`, timestamp: new Date(),\n    };\n    const resultPlaceholder: Message = {\n      id: (Date.now() + 1).toString(), role: \"KIRO\",\n      content: \"\", timestamp: new Date(), isStreaming: true,\n    };\n    setMessages(prev => [...prev, confirmMsg, resultPlaceholder]);\n    setLoading(true);\n\n    try {\n      const res = await api.post(\"/kiro/action\", {\n        action:  action.action,\n        payload: action.payload || {},\n        storeId: effectiveStoreId,\n      });\n      const result = res.data?.data?.result || res.data?.result || \"Done.\";\n      setMessages(prev => prev.map(m =>\n        m.id === resultPlaceholder.id ? { ...m, content: result, isStreaming: false } : m\n      ));\n      toast.success(`KIRO: ${action.label} complete`);\n    } catch (err: any) {\n      setMessages(prev => prev.map(m =>\n        m.id === resultPlaceholder.id ? { ...m, content: \"I could not complete that action - the backend may be offline.\", isStreaming: false } : m\n      ));\n    } finally {\n      setLoading(false);\n    }\n  }, [effectiveStoreId]);\n\n  // ── Send message with real SSE streaming ──────────────────\n  const send = useCallback(async (overrideText?: string) => {\n    const text = (overrideText || input).trim();\n    if (!text || loading) return;\n    setInput(\"\");\n\n    const userMsg: Message = {\n      id: Date.now().toString(), role: \"user\",\n      content: text, timestamp: new Date(),\n    };\n    const kiroPlaceholder: Message = {\n      id: (Date.now() + 1).toString(), role: \"KIRO\",\n      content: \"\", timestamp: new Date(), isStreaming: true,\n    };\n\n    setMessages(prev => [...prev, userMsg, kiroPlaceholder]);\n    setLoading(true);\n\n    try {\n      abortRef.current = new AbortController();\n\n      // Try real SSE streaming first\n      const streamRes = await fetch(\n        `${process.env.NEXT_PUBLIC_API_URL || \"https://dropos-v2.onrender.com/api\"}/kiro/smart-chat`,\n        {\n          method:  \"POST\",\n          headers: {\n            \"Content-Type\":  \"application/json\",\n            \"Authorization\": `Bearer ${useAuthStore.getState().accessToken || \"\"}`,\n            \"Accept\":        \"text/event-stream\",\n          },\n          body:   JSON.stringify({ message: text, storeId: effectiveStoreId, sessionId: sessionId || undefined }),\n          signal: abortRef.current.signal,\n        }\n      );\n\n      if (streamRes.ok && streamRes.headers.get(\"content-type\")?.includes(\"text/event-stream\")) {\n        // Real SSE streaming\n        const reader  = streamRes.body!.getReader();\n        const decoder = new TextDecoder();\n        let fullText  = \"\";\n        let actions: any[] = [];\n\n        while (true) {\n          const { done, value } = await reader.read();\n          if (done) break;\n\n          const chunk = decoder.decode(value, { stream: true });\n          const lines = chunk.split(\"\\n\");\n\n          for (const line of lines) {\n            if (line.startsWith(\"data: \")) {\n              const data = line.slice(6).trim();\n              if (data === \"[DONE]\") {\n                setMessages(prev => prev.map(m =>\n                  m.id === kiroPlaceholder.id ? { ...m, content: fullText, isStreaming: false, actions } : m\n                ));\n                break;\n              }\n              try {\n                const parsed = JSON.parse(data);\n                if (parsed.type === \"text_delta\" && parsed.delta) {\n                  fullText += parsed.delta;\n                  setMessages(prev => prev.map(m =>\n                    m.id === kiroPlaceholder.id ? { ...m, content: fullText, isStreaming: true } : m\n                  ));\n                  bottomRef.current?.scrollIntoView({ behavior: \"smooth\" });\n                } else if (parsed.type === \"actions\") {\n                  actions = parsed.actions || [];\n                } else if (parsed.session_id && !sessionId) {\n                  setSessionId(parsed.session_id);\n                }\n              } catch (_) {\n                // Non-JSON line, skip\n              }\n            }\n          }\n        }\n      } else {\n        // Fallback: non-streaming endpoint\n        const res = await api.post(\"/kiro/smart-chat\", {\n          message: text, storeId: effectiveStoreId, sessionId: sessionId || undefined,\n        });\n        const { reply, session_id, actions = [] } = res.data.data || res.data;\n        if (session_id && !sessionId) setSessionId(session_id);\n\n        // Animate word-by-word for non-streaming fallback\n        const words = (reply || \"I am here. How can I help?\").split(\" \");\n        let displayed = \"\";\n        for (let i = 0; i < words.length; i++) {\n          await new Promise(r => setTimeout(r, 15 + Math.random() * 8));\n          displayed += (i === 0 ? \"\" : \" \") + words[i];\n          setMessages(prev => prev.map(m =>\n            m.id === kiroPlaceholder.id ? { ...m, content: displayed, isStreaming: true } : m\n          ));\n          bottomRef.current?.scrollIntoView({ behavior: \"smooth\" });\n        }\n        setMessages(prev => prev.map(m =>\n          m.id === kiroPlaceholder.id ? { ...m, content: reply || \"I am here. How can I help?\", isStreaming: false, actions } : m\n        ));\n      }\n    } catch (err: any) {\n      if (err.name === \"AbortError\") return;\n      setMessages(prev => prev.map(m =>\n        m.id === kiroPlaceholder.id ? { ...m, content: \"Something went wrong. Please check your connection and try again.\", isStreaming: false } : m\n      ));\n    } finally {\n      setLoading(false);\n    }\n  }, [input, loading, effectiveStoreId, sessionId]);\n\n  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {\n    if (e.key === \"Enter\" && !e.shiftKey) { e.preventDefault(); send(); }\n  };\n\n  const clear = () => { setMessages([]); setSessionId(\"\"); };\n  const isEmpty = messages.length === 0;\n\n  return (\n    <div className={`flex flex-col ${className || \"h-full\"}`}\n      style={{ background: \"#0a0a14\", fontFamily: \"'Plus Jakarta Sans', system-ui, sans-serif\" }}>\n\n      {/* Header */}\n      <div style={{ display: \"flex\", alignItems: \"center\", justifyContent: \"space-between\", padding: \"12px 16px\", borderBottom: \"1px solid rgba(255,255,255,0.06)\", flexShrink: 0 }}>\n        <div style={{ display: \"flex\", alignItems: \"center\", gap: 10 }}>\n          <KIROAvatar size={30} />\n          <div>\n            <p style={{ fontSize: 14, fontWeight: 800, color: \"#fff\", letterSpacing: \"-0.02em\" }}>KIRO</p>\n            <div style={{ display: \"flex\", alignItems: \"center\", gap: 5 }}>\n              <motion.div style={{ width: 6, height: 6, borderRadius: \"50%\", background: \"#10B981\" }}\n                animate={{ opacity: [1, 0.4, 1] }} transition={{ duration: 2, repeat: Infinity }} />\n              <p style={{ fontSize: 11, color: \"rgba(255,255,255,0.35)\" }}>Your AI business partner</p>\n            </div>\n          </div>\n        </div>\n        {messages.length > 0 && (\n          <button onClick={clear} style={{ padding: \"6px 10px\", borderRadius: 8, border: \"1px solid rgba(255,255,255,0.08)\", background: \"transparent\", color: \"rgba(255,255,255,0.35)\", fontSize: 11, cursor: \"pointer\" }}>\n            Clear\n          </button>\n        )}\n      </div>\n\n      {/* Messages */}\n      <div className=\"hide-scroll\" style={{ flex: 1, overflowY: \"auto\", padding: \"16px\", display: \"flex\", flexDirection: \"column\", gap: 16 }}>\n        {isEmpty ? (\n          <div style={{ flex: 1, display: \"flex\", flexDirection: \"column\", alignItems: \"center\", justifyContent: \"center\", textAlign: \"center\", padding: \"24px 16px\" }}>\n            <motion.div initial={{ scale: 0.8, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}\n              style={{ width: 64, height: 64, borderRadius: 20, background: \"linear-gradient(145deg,#6B35E8,#1A0D3D)\", display: \"flex\", alignItems: \"center\", justifyContent: \"center\", marginBottom: 16, boxShadow: \"0 8px 32px rgba(107,53,232,0.4)\" }}>\n              <Zap size={28} color=\"white\" />\n            </motion.div>\n            <p style={{ fontSize: 18, fontWeight: 800, color: \"#fff\", marginBottom: 8, letterSpacing: \"-0.03em\" }}>\n              Good {new Date().getHours() < 12 ? \"morning\" : new Date().getHours() < 17 ? \"afternoon\" : \"evening\"} 👋\n            </p>\n            <p style={{ fontSize: 13, color: \"rgba(255,255,255,0.38)\", marginBottom: 24, maxWidth: 300, lineHeight: 1.6 }}>\n              I am KIRO. I run your store, find winning products, write your ads, and grow your revenue. What do you need?\n            </p>\n            <div style={{ display: \"grid\", gridTemplateColumns: \"1fr 1fr\", gap: 8, width: \"100%\", maxWidth: 380 }}>\n              {QUICK_CHIPS.map(chip => (\n                <button key={chip.label} onClick={() => send(chip.prompt)}\n                  style={{ padding: \"10px 12px\", borderRadius: 12, border: \"1px solid rgba(255,255,255,0.07)\", background: \"rgba(255,255,255,0.03)\", cursor: \"pointer\", textAlign: \"left\", transition: \"all 0.15s\" }}\n                  onMouseEnter={e => (e.currentTarget.style.borderColor = \"rgba(107,53,232,0.4)\")}\n                  onMouseLeave={e => (e.currentTarget.style.borderColor = \"rgba(255,255,255,0.07)\")}>\n                  <span style={{ fontSize: 16, display: \"block\", marginBottom: 2 }}>{chip.icon}</span>\n                  <span style={{ fontSize: 11, fontWeight: 600, color: \"rgba(255,255,255,0.6)\" }}>{chip.label}</span>\n                </button>\n              ))}\n            </div>\n          </div>\n        ) : (\n          messages.map(msg => (\n            <MessageBubble key={msg.id} msg={msg} onAction={executeAction} onCopy={() => {}} />\n          ))\n        )}\n        <div ref={bottomRef} />\n      </div>\n\n      {/* Input */}\n      <div style={{ padding: \"12px 16px\", borderTop: \"1px solid rgba(255,255,255,0.06)\", flexShrink: 0 }}>\n        <div style={{ display: \"flex\", alignItems: \"flex-end\", gap: 8, background: \"rgba(255,255,255,0.05)\", border: \"1px solid rgba(255,255,255,0.1)\", borderRadius: 16, padding: \"8px 8px 8px 14px\", transition: \"border-color 0.15s\" }}>\n          <textarea\n            ref={inputRef}\n            value={input}\n            onChange={e => setInput(e.target.value)}\n            onKeyDown={handleKeyDown}\n            placeholder=\"Ask KIRO anything about your store...\"\n            rows={1}\n            disabled={loading}\n            style={{ flex: 1, background: \"transparent\", border: \"none\", outline: \"none\", color: \"#fff\", fontSize: 14, lineHeight: 1.6, resize: \"none\", maxHeight: 120, fontFamily: \"inherit\" }}\n            onInput={e => {\n              const t = e.target as HTMLTextAreaElement;\n              t.style.height = \"auto\";\n              t.style.height = Math.min(t.scrollHeight, 120) + \"px\";\n            }}\n          />\n          <motion.button\n            onClick={() => send()}\n            disabled={!input.trim() || loading}\n            whileTap={{ scale: 0.92 }}\n            style={{ width: 34, height: 34, borderRadius: 10, border: \"none\", cursor: input.trim() && !loading ? \"pointer\" : \"not-allowed\", display: \"flex\", alignItems: \"center\", justifyContent: \"center\", flexShrink: 0, background: input.trim() && !loading ? \"linear-gradient(135deg,#6B35E8,#3D1C8A)\" : \"rgba(255,255,255,0.06)\", transition: \"all 0.15s\" }}>\n            {loading\n              ? <Loader2 size={15} color=\"rgba(255,255,255,0.5)\" style={{ animation: \"spin 1s linear infinite\" }} />\n              : <Send size={14} color={input.trim() ? \"white\" : \"rgba(255,255,255,0.25)\"} />\n            }\n          </motion.button>\n        </div>\n        <p style={{ fontSize: 10, color: \"rgba(255,255,255,0.15)\", textAlign: \"center\", marginTop: 8 }}>\n          KIRO can make mistakes. Always verify important decisions.\n        </p>\n      </div>\n    </div>\n  );\n}\n","frontend/src/app/layout.tsx":"// src/app/layout.tsx\nimport type { Metadata, Viewport } from \"next\";\nimport \"./globals.css\";\nimport { Providers } from \"../components/layout/Providers\";\nimport Script from \"next/script\";\n\nexport const metadata: Metadata = {\n  title:       { default: \"DropOS\", template: \"%s | DropOS\" },\n  description: \"The complete SaaS dropshipping platform. Launch your store in minutes.\",\n  keywords:    [\"dropshipping\",\"ecommerce\",\"saas\",\"store builder\",\"KIRO\",\"AI\"],\n  authors:     [{ name: \"DropOS\" }],\n  manifest:    \"/manifest.json\",\n  appleWebApp: {\n    capable:        true,\n    statusBarStyle: \"black-translucent\",\n    title:          \"DropOS\",\n    startupImage:   \"/icons/icon-512.png\",\n  },\n  formatDetection: { telephone: false },\n  openGraph: {\n    type:        \"website\",\n    locale:      \"en_NG\",\n    url:         process.env.NEXT_PUBLIC_APP_URL,\n    siteName:    \"DropOS\",\n    title:       \"DropOS - Launch Your Store in 60 Seconds with KIRO\",\n    description: \"KIRO builds your dropshipping store, finds winning products, and grows your revenue. Free to start.\",\n    images:      [{ url: \"/icons/icon-512.png\", width: 512, height: 512 }],\n  },\n  twitter: { card: \"summary_large_image\", title: \"DropOS\" },\n  icons: {\n    icon:  [\n      { url: \"/icons/icon-32.png\",  sizes: \"32x32\",  type: \"image/png\" },\n      { url: \"/icons/icon-192.png\", sizes: \"192x192\", type: \"image/png\" },\n    ],\n    apple: [\n      { url: \"/icons/icon-152.png\", sizes: \"152x152\" },\n      { url: \"/icons/icon-192.png\", sizes: \"192x192\" },\n    ],\n  },\n};\n\nexport const viewport: Viewport = {\n  themeColor: [\n    { media: \"(prefers-color-scheme: dark)\",  color: \"#0F172A\" },\n    { media: \"(prefers-color-scheme: light)\", color: \"#F8FAFC\" },\n  ],\n  width:        \"device-width\",\n  initialScale: 1,\n  maximumScale: 1,\n  userScalable: false,\n  viewportFit:  \"cover\",\n};\n\nexport default function RootLayout({ children }: { children: React.ReactNode }) {\n  return (\n    <html lang=\"en\" suppressHydrationWarning>\n      <head>\n        <link rel=\"manifest\" href=\"/manifest.json\" />\n        <meta name=\"mobile-web-app-capable\" content=\"yes\" />\n        <meta name=\"apple-mobile-web-app-capable\" content=\"yes\" />\n        <meta name=\"apple-mobile-web-app-status-bar-style\" content=\"black-translucent\" />\n        <meta name=\"apple-mobile-web-app-title\" content=\"DropOS\" />\n        <meta name=\"application-name\" content=\"DropOS\" />\n        <meta name=\"msapplication-TileColor\" content=\"#7C3AED\" />\n        <meta name=\"msapplication-tap-highlight\" content=\"no\" />\n        <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\" />\n        <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossOrigin=\"anonymous\" />\n      </head>\n      <body>\n        <Providers>{children}</Providers>\n        {/* Service Worker registration */}\n        <Script id=\"sw-register\" strategy=\"afterInteractive\">{\n          `if ('serviceWorker' in navigator) {\n            window.addEventListener('load', function() {\n              navigator.serviceWorker.register('/sw-custom.js', { scope: '/' })\n                .then(r => console.log('[DropOS PWA] Service worker registered:', r.scope))\n                .catch(e => console.log('[DropOS PWA] SW registration failed:', e));\n            });\n          }`\n        }</Script>\n      </body>\n    </html>\n  );\n}\n","frontend/src/store/credits.store.ts":"import { create } from \"zustand\";\nimport { persist } from \"zustand/middleware\";\n\nexport interface CreditsState {\n  balance:      number;\n  plan:         \"FREE\" | \"GROWTH\" | \"PRO\";\n  monthlyLimit: number;\n  usedThisMonth: number;\n  lastRefresh:  string | null;\n  // Actions\n  setBalance:   (b: number) => void;\n  setPlan:      (p: \"FREE\" | \"GROWTH\" | \"PRO\") => void;\n  deduct:       (amount: number) => boolean; // returns false if insufficient\n  setFromAPI:   (data: { balance: number; plan: string; monthlyLimit: number; usedThisMonth: number }) => void;\n}\n\nconst PLAN_LIMITS: Record<string, number> = {\n  FREE:   500,\n  GROWTH: 3000,\n  PRO:    10000,\n};\n\nexport const useCreditsStore = create<CreditsState>()(\n  persist(\n    (set, get) => ({\n      balance:       500,\n      plan:          \"FREE\",\n      monthlyLimit:  500,\n      usedThisMonth: 0,\n      lastRefresh:   null,\n\n      setBalance:  (balance)  => set({ balance }),\n      setPlan:     (plan)     => set({ plan, monthlyLimit: PLAN_LIMITS[plan] || 500 }),\n\n      deduct: (amount) => {\n        const { balance } = get();\n        if (balance < amount) return false;\n        set(s => ({ balance: s.balance - amount, usedThisMonth: s.usedThisMonth + amount }));\n        return true;\n      },\n\n      setFromAPI: ({ balance, plan, monthlyLimit, usedThisMonth }) => {\n        set({ balance, plan: plan as any, monthlyLimit, usedThisMonth });\n      },\n    }),\n    { name: \"dropos-credits\" }\n  )\n);\n\n// Credit costs for each feature\nexport const CREDIT_COSTS = {\n  kiro_message:     1,\n  image_generate:   5,\n  image_lifestyle:  8,\n  image_background: 3,\n  tiktok_script:    3,\n  ad_copy:          2,\n  product_desc:     2,\n  competitor_spy:   5,\n  product_research: 4,\n  store_build:      20,\n  video_short:      20,\n  video_standard:   50,\n  video_hd:         100,\n} as const;\n","frontend/src/components/ui/CreditWallet.tsx":"\"use client\";\nimport { useState, useEffect } from \"react\";\nimport { motion, AnimatePresence } from \"framer-motion\";\nimport { Zap, Plus, TrendingUp, AlertTriangle, X, Check } from \"lucide-react\";\nimport { useCreditsStore, CREDIT_COSTS } from \"../../store/credits.store\";\nimport { api } from \"../../lib/api\";\nimport toast from \"react-hot-toast\";\n\nconst TOP_UP_PACKS = [\n  { id: \"starter\",    amount: 500,   price: 1500,   label: \"Starter\",    popular: false },\n  { id: \"growth\",     amount: 2000,  price: 5000,   label: \"Growth\",     popular: true  },\n  { id: \"pro\",        amount: 5000,  price: 10000,  label: \"Pro\",        popular: false },\n  { id: \"unlimited\",  amount: 15000, price: 25000,  label: \"Unlimited\",  popular: false },\n];\n\nexport function CreditBadge({ compact = false }: { compact?: boolean }) {\n  const { balance, monthlyLimit } = useCreditsStore();\n  const pct = Math.round((balance / monthlyLimit) * 100);\n  const isLow = pct <= 20;\n  const isCritical = pct <= 5;\n\n  const color = isCritical ? \"#EF4444\" : isLow ? \"#F59E0B\" : \"#10B981\";\n  const bg    = isCritical ? \"rgba(239,68,68,0.1)\" : isLow ? \"rgba(245,158,11,0.1)\" : \"rgba(107,53,232,0.1)\";\n\n  if (compact) {\n    return (\n      <div style={{ display: \"flex\", alignItems: \"center\", gap: 5, padding: \"4px 10px\", borderRadius: 20, background: bg, border: `1px solid ${color}30` }}>\n        <Zap size={11} color={color} />\n        <span style={{ fontSize: 11, fontWeight: 700, color }}>{balance.toLocaleString()}</span>\n      </div>\n    );\n  }\n\n  return (\n    <div style={{ display: \"flex\", alignItems: \"center\", gap: 8 }}>\n      <Zap size={13} color={color} />\n      <div style={{ flex: 1 }}>\n        <div style={{ display: \"flex\", justifyContent: \"space-between\", marginBottom: 3 }}>\n          <span style={{ fontSize: 11, fontWeight: 600, color: \"rgba(255,255,255,0.6)\" }}>Credits</span>\n          <span style={{ fontSize: 11, fontWeight: 700, color }}>{balance.toLocaleString()} / {monthlyLimit.toLocaleString()}</span>\n        </div>\n        <div style={{ height: 4, borderRadius: 99, background: \"rgba(255,255,255,0.08)\", overflow: \"hidden\" }}>\n          <motion.div\n            initial={{ width: 0 }}\n            animate={{ width: `${pct}%` }}\n            transition={{ duration: 0.8, ease: \"easeOut\" }}\n            style={{ height: \"100%\", borderRadius: 99, background: color }}\n          />\n        </div>\n      </div>\n    </div>\n  );\n}\n\nexport function CreditCost({ feature, children }: { feature: keyof typeof CREDIT_COSTS; children?: React.ReactNode }) {\n  const { balance } = useCreditsStore();\n  const cost = CREDIT_COSTS[feature];\n  const canAfford = balance >= cost;\n\n  return (\n    <div style={{ display: \"flex\", alignItems: \"center\", gap: 6 }}>\n      {children}\n      <span style={{ fontSize: 11, fontWeight: 600, color: canAfford ? \"#A78BFA\" : \"#EF4444\", display: \"flex\", alignItems: \"center\", gap: 3 }}>\n        <Zap size={10} />\n        {cost} credits\n        {!canAfford && <AlertTriangle size={10} color=\"#EF4444\" />}\n      </span>\n    </div>\n  );\n}\n\nexport function TopUpModal({ onClose }: { onClose: () => void }) {\n  const [loading, setLoading] = useState<string | null>(null);\n  const { setBalance, balance } = useCreditsStore();\n\n  const handleTopUp = async (pack: typeof TOP_UP_PACKS[0]) => {\n    setLoading(pack.id);\n    try {\n      const res = await api.post(\"/billing/credits/topup\", { packId: pack.id });\n      const url = res.data?.data?.authorizationUrl;\n      if (url) {\n        window.location.href = url;\n      } else {\n        // Demo mode - just add credits\n        setBalance(balance + pack.amount);\n        toast.success(`Added ${pack.amount.toLocaleString()} credits!`);\n        onClose();\n      }\n    } catch {\n      toast.error(\"Top-up failed - backend offline\");\n    } finally {\n      setLoading(null);\n    }\n  };\n\n  return (\n    <div style={{ position: \"fixed\", inset: 0, zIndex: 9999, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", padding: 16, background: \"rgba(0,0,0,0.7)\", backdropFilter: \"blur(8px)\" }}\n      onClick={e => e.target === e.currentTarget && onClose()}>\n      <motion.div initial={{ opacity: 0, scale: 0.95, y: 16 }} animate={{ opacity: 1, scale: 1, y: 0 }}\n        style={{ width: \"100%\", maxWidth: 420, borderRadius: 24, background: \"#181230\", border: \"1px solid rgba(255,255,255,0.08)\", overflow: \"hidden\" }}>\n        <div style={{ display: \"flex\", alignItems: \"center\", justifyContent: \"space-between\", padding: \"20px 24px\", borderBottom: \"1px solid rgba(255,255,255,0.06)\" }}>\n          <div>\n            <h2 style={{ fontSize: 16, fontWeight: 800, color: \"#fff\", marginBottom: 2 }}>Top Up Credits</h2>\n            <p style={{ fontSize: 12, color: \"rgba(255,255,255,0.4)\" }}>Credits never expire. Use for KIRO, images, videos.</p>\n          </div>\n          <button onClick={onClose} style={{ color: \"rgba(255,255,255,0.4)\", background: \"none\", border: \"none\", cursor: \"pointer\" }}><X size={18} /></button>\n        </div>\n\n        <div style={{ padding: 24, display: \"grid\", gridTemplateColumns: \"1fr 1fr\", gap: 12 }}>\n          {TOP_UP_PACKS.map(pack => (\n            <button key={pack.id} onClick={() => handleTopUp(pack)} disabled={!!loading}\n              style={{ padding: \"16px\", borderRadius: 16, border: `1px solid ${pack.popular ? \"rgba(107,53,232,0.5)\" : \"rgba(255,255,255,0.08)\"}`, background: pack.popular ? \"rgba(107,53,232,0.1)\" : \"rgba(255,255,255,0.03)\", cursor: \"pointer\", textAlign: \"left\", position: \"relative\", opacity: loading ? 0.6 : 1 }}>\n              {pack.popular && <span style={{ position: \"absolute\", top: -8, right: 8, fontSize: 9, fontWeight: 700, padding: \"2px 8px\", borderRadius: 99, background: \"#6B35E8\", color: \"#fff\", letterSpacing: \"0.05em\", textTransform: \"uppercase\" }}>Popular</span>}\n              {loading === pack.id\n                ? <div style={{ height: 40, display: \"flex\", alignItems: \"center\", justifyContent: \"center\" }}>\n                    <motion.div animate={{ rotate: 360 }} transition={{ duration: 1, repeat: Infinity, ease: \"linear\" }}><Zap size={16} color=\"#8B5CF6\" /></motion.div>\n                  </div>\n                : <>\n                    <p style={{ fontSize: 20, fontWeight: 900, color: \"#fff\", marginBottom: 2 }}>{pack.amount.toLocaleString()}</p>\n                    <p style={{ fontSize: 11, color: \"rgba(255,255,255,0.4)\", marginBottom: 10 }}>credits</p>\n                    <p style={{ fontSize: 15, fontWeight: 800, color: \"#A78BFA\" }}>₦{pack.price.toLocaleString()}</p>\n                  </>\n              }\n            </button>\n          ))}\n        </div>\n\n        <div style={{ padding: \"0 24px 24px\" }}>\n          <div style={{ padding: \"12px 16px\", borderRadius: 12, background: \"rgba(107,53,232,0.06)\", border: \"1px solid rgba(107,53,232,0.15)\", fontSize: 12, color: \"rgba(255,255,255,0.45)\", lineHeight: 1.6 }}>\n            Top-up credits roll over forever. Monthly plan credits reset each billing date. KIRO uses 1 credit per message.\n          </div>\n        </div>\n      </motion.div>\n    </div>\n  );\n}\n\nexport default function CreditWallet() {\n  const { balance, plan, monthlyLimit, usedThisMonth } = useCreditsStore();\n  const [showTopUp, setShowTopUp] = useState(false);\n  const pct = Math.round((balance / monthlyLimit) * 100);\n  const isLow = pct <= 20;\n\n  return (\n    <>\n      <div style={{ padding: \"14px 16px\", borderRadius: 16, background: \"rgba(107,53,232,0.08)\", border: \"1px solid rgba(107,53,232,0.2)\" }}>\n        <div style={{ display: \"flex\", alignItems: \"center\", justifyContent: \"space-between\", marginBottom: 10 }}>\n          <div style={{ display: \"flex\", alignItems: \"center\", gap: 6 }}>\n            <Zap size={14} color=\"#8B5CF6\" />\n            <span style={{ fontSize: 13, fontWeight: 700, color: \"#fff\" }}>KIRO Credits</span>\n          </div>\n          <button onClick={() => setShowTopUp(true)}\n            style={{ display: \"flex\", alignItems: \"center\", gap: 4, padding: \"4px 10px\", borderRadius: 8, border: \"1px solid rgba(107,53,232,0.4)\", background: \"rgba(107,53,232,0.12)\", color: \"#A78BFA\", fontSize: 11, fontWeight: 600, cursor: \"pointer\" }}>\n            <Plus size={10} /> Top Up\n          </button>\n        </div>\n\n        <div style={{ display: \"flex\", alignItems: \"baseline\", gap: 4, marginBottom: 8 }}>\n          <span style={{ fontSize: 24, fontWeight: 900, color: isLow ? \"#F59E0B\" : \"#fff\" }}>{balance.toLocaleString()}</span>\n          <span style={{ fontSize: 12, color: \"rgba(255,255,255,0.35)\" }}>/ {monthlyLimit.toLocaleString()} this month</span>\n        </div>\n\n        <div style={{ height: 5, borderRadius: 99, background: \"rgba(255,255,255,0.08)\", overflow: \"hidden\", marginBottom: 8 }}>\n          <motion.div initial={{ width: 0 }} animate={{ width: `${pct}%` }} transition={{ duration: 0.8 }}\n            style={{ height: \"100%\", borderRadius: 99, background: isLow ? (pct <= 5 ? \"#EF4444\" : \"#F59E0B\") : \"#6B35E8\" }} />\n        </div>\n\n        {isLow && (\n          <div style={{ display: \"flex\", alignItems: \"center\", gap: 5, fontSize: 11, color: pct <= 5 ? \"#F87171\" : \"#FCD34D\" }}>\n            <AlertTriangle size={11} />\n            {pct <= 5 ? \"Almost out! Top up to keep KIRO running.\" : \"Running low on credits.\"}\n          </div>\n        )}\n      </div>\n\n      <AnimatePresence>\n        {showTopUp && <TopUpModal onClose={() => setShowTopUp(false)} />}\n      </AnimatePresence>\n    </>\n  );\n}\n","frontend/src/components/ui/PlanGate.tsx":"\"use client\";\nimport { useState } from \"react\";\nimport { motion, AnimatePresence } from \"framer-motion\";\nimport { Zap, X, ArrowRight, Crown, Lock } from \"lucide-react\";\nimport { useAuthStore } from \"../../store/auth.store\";\nimport Link from \"next/link\";\n\ntype Feature =\n  | \"products\"   // Free: 20, Growth+: unlimited\n  | \"stores\"     // Free+Growth: 1, Pro: unlimited\n  | \"kiro\"       // Free: 10/day, Growth+: unlimited\n  | \"analytics\"  // Free: basic, Growth+: full\n  | \"domain\"     // Free: no, Growth+: yes\n  | \"branding\"   // Free: required, Growth+: removable\n  | \"campaigns\"  // Pro only\n  | \"loyalty\"    // Pro only\n  | \"whatsapp\"   // Pro only\n  | \"api\"        // Pro only\n  | \"staff\";     // Pro only: 3 accounts\n\nconst PLAN_REQUIREMENTS: Record<Feature, \"FREE\" | \"GROWTH\" | \"PRO\"> = {\n  products:  \"GROWTH\",\n  stores:    \"PRO\",\n  kiro:      \"GROWTH\",\n  analytics: \"GROWTH\",\n  domain:    \"GROWTH\",\n  branding:  \"GROWTH\",\n  campaigns: \"PRO\",\n  loyalty:   \"PRO\",\n  whatsapp:  \"PRO\",\n  api:       \"PRO\",\n  staff:     \"PRO\",\n};\n\nconst UPGRADE_COPY: Record<Feature, { title: string; desc: string; cta: string }> = {\n  products:  { title: \"Upgrade to add more products\", desc: \"You've hit the 20 product limit on your free plan. Growth gives you unlimited products.\", cta: \"Upgrade to Growth - ₦9,500/mo\" },\n  stores:    { title: \"Multiple stores on Pro\", desc: \"Run unlimited stores on Pro. Your Growth plan includes 1 store.\", cta: \"Upgrade to Pro - ₦25,000/mo\" },\n  kiro:      { title: \"Unlimited KIRO on Growth\", desc: \"You've used your 10 free KIRO messages today. Upgrade for unlimited chat.\", cta: \"Upgrade to Growth - ₦9,500/mo\" },\n  analytics: { title: \"Full analytics on Growth\", desc: \"See LTV, cohorts, and revenue attribution with a Growth plan.\", cta: \"Upgrade to Growth - ₦9,500/mo\" },\n  domain:    { title: \"Custom domain on Growth\", desc: \"Remove the dropos.io subdomain and use your own domain.\", cta: \"Upgrade to Growth - ₦9,500/mo\" },\n  branding:  { title: \"Remove DropOS branding\", desc: \"Show your brand, not ours. Available on Growth and above.\", cta: \"Upgrade to Growth - ₦9,500/mo\" },\n  campaigns: { title: \"Email campaigns on Pro\", desc: \"Send broadcast emails to your customer segments.\", cta: \"Upgrade to Pro - ₦25,000/mo\" },\n  loyalty:   { title: \"Loyalty programme on Pro\", desc: \"Keep customers coming back with points and rewards.\", cta: \"Upgrade to Pro - ₦25,000/mo\" },\n  whatsapp:  { title: \"WhatsApp Commerce on Pro\", desc: \"KIRO handles all customer WhatsApp messages automatically, 24/7.\", cta: \"Upgrade to Pro - ₦25,000/mo\" },\n  api:       { title: \"API access on Pro\", desc: \"Build on top of DropOS with full API access.\", cta: \"Upgrade to Pro - ₦25,000/mo\" },\n  staff:     { title: \"Staff accounts on Pro\", desc: \"Add up to 3 team members to manage your store.\", cta: \"Upgrade to Pro - ₦25,000/mo\" },\n};\n\nfunction getPlanLevel(plan: string): number {\n  if (plan === \"PRO\")    return 3;\n  if (plan === \"GROWTH\") return 2;\n  return 1; // FREE\n}\n\nfunction meetsRequirement(userPlan: string, required: string): boolean {\n  return getPlanLevel(userPlan) >= getPlanLevel(required);\n}\n\ninterface PlanGateProps {\n  feature:   Feature;\n  children:  React.ReactNode;\n  fallback?: React.ReactNode;\n  silent?:   boolean; // just hide, no modal\n}\n\nexport function PlanGate({ feature, children, fallback, silent }: PlanGateProps) {\n  const user    = useAuthStore(s => s.user);\n  const plan    = user?.subscription?.plan || \"FREE\";\n  const required = PLAN_REQUIREMENTS[feature];\n\n  if (meetsRequirement(plan, required)) return <>{children}</>;\n  if (silent) return fallback ? <>{fallback}</> : null;\n\n  return (\n    <>\n      {fallback || (\n        <div style={{ opacity: 0.4, pointerEvents: \"none\", filter: \"grayscale(0.5)\" }}>\n          {children}\n        </div>\n      )}\n      <UpgradePrompt feature={feature} requiredPlan={required} />\n    </>\n  );\n}\n\nexport function UpgradePrompt({ feature, requiredPlan, inline = false }: { feature: Feature; requiredPlan: string; inline?: boolean }) {\n  const [dismissed, setDismissed] = useState(false);\n  const copy = UPGRADE_COPY[feature];\n  const color = requiredPlan === \"PRO\" ? \"#F59E0B\" : \"#8B5CF6\";\n  const bg    = requiredPlan === \"PRO\" ? \"rgba(245,158,11,0.08)\" : \"rgba(107,53,232,0.08)\";\n\n  if (dismissed && inline) return null;\n\n  if (inline) {\n    return (\n      <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}\n        style={{ padding: \"14px 16px\", borderRadius: 14, background: bg, border: `1px solid ${color}30`, display: \"flex\", alignItems: \"center\", gap: 12 }}>\n        <div style={{ width: 32, height: 32, borderRadius: 10, background: `${color}15`, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", flexShrink: 0 }}>\n          {requiredPlan === \"PRO\" ? <Crown size={14} color={color} /> : <Zap size={14} color={color} />}\n        </div>\n        <div style={{ flex: 1 }}>\n          <p style={{ fontSize: 13, fontWeight: 700, color: \"#fff\", marginBottom: 2 }}>{copy.title}</p>\n          <p style={{ fontSize: 12, color: \"rgba(255,255,255,0.45)\", lineHeight: 1.5 }}>{copy.desc}</p>\n        </div>\n        <Link href=\"/dashboard/billing\">\n          <button style={{ display: \"flex\", alignItems: \"center\", gap: 6, padding: \"8px 14px\", borderRadius: 10, border: \"none\", background: `linear-gradient(135deg,${color},${color}99)`, color: \"#fff\", fontSize: 12, fontWeight: 700, cursor: \"pointer\", whiteSpace: \"nowrap\" }}>\n            Upgrade <ArrowRight size={11} />\n          </button>\n        </Link>\n        <button onClick={() => setDismissed(true)} style={{ color: \"rgba(255,255,255,0.3)\", background: \"none\", border: \"none\", cursor: \"pointer\" }}><X size={14} /></button>\n      </motion.div>\n    );\n  }\n\n  return null;\n}\n\n// Usage limit progress bar — shown when approaching limits\nexport function UsageBar({ feature, current, max, label }: { feature: Feature; current: number; max: number; label?: string }) {\n  const pct      = Math.min(100, Math.round((current / max) * 100));\n  const isHigh   = pct >= 80;\n  const isFull   = pct >= 100;\n  const color    = isFull ? \"#EF4444\" : isHigh ? \"#F59E0B\" : \"#6B35E8\";\n\n  return (\n    <div>\n      <div style={{ display: \"flex\", justifyContent: \"space-between\", marginBottom: 4, fontSize: 11 }}>\n        <span style={{ color: \"rgba(255,255,255,0.45)\" }}>{label || feature}</span>\n        <span style={{ color: isHigh ? color : \"rgba(255,255,255,0.45)\", fontWeight: isHigh ? 700 : 400 }}>\n          {current} / {max}\n        </span>\n      </div>\n      <div style={{ height: 4, borderRadius: 99, background: \"rgba(255,255,255,0.08)\", overflow: \"hidden\" }}>\n        <motion.div\n          initial={{ width: 0 }}\n          animate={{ width: `${pct}%` }}\n          transition={{ duration: 0.8 }}\n          style={{ height: \"100%\", borderRadius: 99, background: color }}\n        />\n      </div>\n      {isFull && (\n        <UpgradePrompt feature={feature} requiredPlan={PLAN_REQUIREMENTS[feature]} inline />\n      )}\n    </div>\n  );\n}\n","frontend/src/components/ui/SetupChecklist.tsx":"\"use client\";\nimport { useState, useEffect } from \"react\";\nimport { motion, AnimatePresence } from \"framer-motion\";\nimport { Check, ChevronRight, X, Zap, Package, CreditCard, Share2, ShoppingBag } from \"lucide-react\";\nimport Link from \"next/link\";\nimport { useAuthStore } from \"../../store/auth.store\";\nimport { useQuery } from \"@tanstack/react-query\";\nimport { api } from \"../../lib/api\";\n\ninterface ChecklistStep {\n  id:       string;\n  icon:     React.ElementType;\n  label:    string;\n  desc:     string;\n  href:     string;\n  points:   number;\n  check:    (data: any) => boolean;\n}\n\nconst STEPS: ChecklistStep[] = [\n  {\n    id:     \"store\",\n    icon:   ShoppingBag,\n    label:  \"Create your store\",\n    desc:   \"Give your store a name and pick a theme\",\n    href:   \"/dashboard/stores\",\n    points: 20,\n    check:  d => !!(d?.stores?.[0]?.name),\n  },\n  {\n    id:     \"product\",\n    icon:   Package,\n    label:  \"Add your first product\",\n    desc:   \"Add at least one product to your store\",\n    href:   \"/dashboard/products\",\n    points: 20,\n    check:  d => (d?.productCount || 0) > 0,\n  },\n  {\n    id:     \"kiro\",\n    icon:   Zap,\n    label:  \"Chat with KIRO\",\n    desc:   \"Ask KIRO to help set up your store\",\n    href:   \"/dashboard/kiro\",\n    points: 20,\n    check:  d => (d?.kiroMessageCount || 0) > 0,\n  },\n  {\n    id:     \"payment\",\n    icon:   CreditCard,\n    label:  \"Connect payments\",\n    desc:   \"Set up Paystack to start receiving money\",\n    href:   \"/dashboard/settings\",\n    points: 20,\n    check:  d => !!(d?.stores?.[0]?.paystackConnected),\n  },\n  {\n    id:     \"share\",\n    icon:   Share2,\n    label:  \"Share your store\",\n    desc:   \"Send your store link to your first customer\",\n    href:   \"/dashboard/stores\",\n    points: 20,\n    check:  d => (d?.orderCount || 0) > 0,\n  },\n];\n\nexport default function SetupChecklist() {\n  const user    = useAuthStore(s => s.user);\n  const [dismissed, setDismissed] = useState(false);\n  const [hasShown, setHasShown]   = useState(false);\n\n  const { data } = useQuery({\n    queryKey:  [\"setup-progress\", user?.id],\n    queryFn:   () => api.get(\"/dashboard/setup-progress\").then(r => r.data.data),\n    enabled:   !!user?.id,\n    staleTime: 60000,\n  });\n\n  const progress = STEPS.filter(s => s.check(data || user)).length;\n  const total    = STEPS.length;\n  const pct      = Math.round((progress / total) * 100);\n  const allDone  = progress === total;\n\n  // Auto-dismiss when complete\n  useEffect(() => {\n    if (allDone) {\n      const t = setTimeout(() => setDismissed(true), 3000);\n      return () => clearTimeout(t);\n    }\n  }, [allDone]);\n\n  // Don't show if dismissed or all done\n  if (dismissed || allDone) return null;\n\n  // Only show for new users (< 7 days old)\n  const createdAt  = user?.createdAt ? new Date(user.createdAt) : new Date();\n  const daysSince  = (Date.now() - createdAt.getTime()) / (1000 * 60 * 60 * 24);\n  if (daysSince > 7) return null;\n\n  return (\n    <motion.div\n      initial={{ opacity: 0, y: -12 }}\n      animate={{ opacity: 1, y: 0 }}\n      exit={{ opacity: 0, y: -8 }}\n      style={{ borderRadius: 20, background: \"rgba(107,53,232,0.08)\", border: \"1px solid rgba(107,53,232,0.2)\", overflow: \"hidden\", marginBottom: 24 }}>\n\n      {/* Header */}\n      <div style={{ display: \"flex\", alignItems: \"center\", justifyContent: \"space-between\", padding: \"16px 20px 12px\" }}>\n        <div>\n          <div style={{ display: \"flex\", alignItems: \"center\", gap: 8, marginBottom: 4 }}>\n            <Zap size={15} color=\"#8B5CF6\" />\n            <p style={{ fontSize: 14, fontWeight: 800, color: \"#fff\" }}>\n              {progress === 0 ? \"Let's get your store ready\" : `${progress} of ${total} done - keep going!`}\n            </p>\n          </div>\n          {/* Progress bar */}\n          <div style={{ width: 200, height: 4, borderRadius: 99, background: \"rgba(255,255,255,0.08)\", overflow: \"hidden\" }}>\n            <motion.div\n              initial={{ width: 0 }}\n              animate={{ width: `${pct}%` }}\n              transition={{ duration: 0.8, ease: \"easeOut\" }}\n              style={{ height: \"100%\", borderRadius: 99, background: \"linear-gradient(90deg,#6B35E8,#A78BFA)\" }}\n            />\n          </div>\n        </div>\n        <button onClick={() => setDismissed(true)} style={{ color: \"rgba(255,255,255,0.3)\", background: \"none\", border: \"none\", cursor: \"pointer\" }}>\n          <X size={15} />\n        </button>\n      </div>\n\n      {/* Steps */}\n      <div style={{ display: \"grid\", gridTemplateColumns: \"1fr 1fr\", gap: 1, background: \"rgba(255,255,255,0.05)\" }}>\n        {STEPS.map((step, i) => {\n          const done    = step.check(data || user);\n          const Icon    = step.icon;\n          return (\n            <Link key={step.id} href={done ? \"#\" : step.href} style={{ textDecoration: \"none\" }}>\n              <div style={{ display: \"flex\", alignItems: \"center\", gap: 10, padding: \"12px 16px\", background: done ? \"rgba(16,185,129,0.05)\" : \"rgba(6,4,13,0.5)\", transition: \"background 0.15s\", cursor: done ? \"default\" : \"pointer\" }}>\n                <div style={{ width: 28, height: 28, borderRadius: 8, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", flexShrink: 0, background: done ? \"rgba(16,185,129,0.15)\" : \"rgba(255,255,255,0.06)\", border: `1px solid ${done ? \"rgba(16,185,129,0.3)\" : \"rgba(255,255,255,0.08)\"}` }}>\n                  {done\n                    ? <Check size={13} color=\"#10B981\" strokeWidth={3} />\n                    : <Icon size={13} color=\"rgba(255,255,255,0.5)\" />\n                  }\n                </div>\n                <div style={{ flex: 1, minWidth: 0 }}>\n                  <p style={{ fontSize: 12, fontWeight: done ? 500 : 600, color: done ? \"rgba(255,255,255,0.4)\" : \"rgba(255,255,255,0.85)\", textDecoration: done ? \"line-through\" : \"none\" }}>{step.label}</p>\n                  {!done && <p style={{ fontSize: 10, color: \"rgba(255,255,255,0.3)\", marginTop: 1 }}>{step.desc}</p>}\n                </div>\n                {!done && <ChevronRight size={12} color=\"rgba(255,255,255,0.2)\" />}\n              </div>\n            </Link>\n          );\n        })}\n      </div>\n\n      <div style={{ padding: \"10px 20px 14px\", fontSize: 11, color: \"rgba(255,255,255,0.25)\", textAlign: \"center\" }}>\n        Complete all 5 steps to unlock your full store potential\n      </div>\n    </motion.div>\n  );\n}\n","frontend/src/components/ui/FirstSaleCelebration.tsx":"\"use client\";\nimport { useState, useEffect, useRef } from \"react\";\nimport { motion, AnimatePresence } from \"framer-motion\";\nimport { Zap, X, Share2, ArrowRight } from \"lucide-react\";\nimport Link from \"next/link\";\n\ninterface Props {\n  orderAmount?: number;\n  customerName?: string;\n  onDismiss: () => void;\n}\n\nfunction Particle({ x, y, color, delay }: { x: number; y: number; color: string; delay: number }) {\n  return (\n    <motion.div\n      initial={{ x: \"50%\", y: \"50%\", opacity: 1, scale: 1 }}\n      animate={{ x: `${x}%`, y: `${y}%`, opacity: 0, scale: 0.2 }}\n      transition={{ duration: 1.2 + Math.random() * 0.5, delay, ease: \"easeOut\" }}\n      style={{ position: \"absolute\", width: 8, height: 8, borderRadius: 2, background: color, pointerEvents: \"none\" }}\n    />\n  );\n}\n\nconst CONFETTI_COLORS = [\"#6B35E8\",\"#A78BFA\",\"#10B981\",\"#F59E0B\",\"#EF4444\",\"#06B6D4\",\"#EC4899\",\"#fff\"];\n\nexport default function FirstSaleCelebration({ orderAmount, customerName, onDismiss }: Props) {\n  const particles = Array.from({ length: 60 }, (_, i) => ({\n    id: i,\n    x:  Math.random() * 200 - 50,\n    y:  Math.random() * 200 - 50,\n    color: CONFETTI_COLORS[Math.floor(Math.random() * CONFETTI_COLORS.length)],\n    delay: Math.random() * 0.3,\n  }));\n\n  const fmt = (n: number) => new Intl.NumberFormat(\"en-NG\", { style: \"currency\", currency: \"NGN\", maximumFractionDigits: 0 }).format(n);\n\n  return (\n    <div style={{ position: \"fixed\", inset: 0, zIndex: 99999, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", padding: 16, background: \"rgba(0,0,0,0.8)\", backdropFilter: \"blur(12px)\" }}>\n      {/* Particles */}\n      <div style={{ position: \"absolute\", inset: 0, overflow: \"hidden\", pointerEvents: \"none\" }}>\n        {particles.map(p => <Particle key={p.id} {...p} />)}\n      </div>\n\n      <motion.div\n        initial={{ opacity: 0, scale: 0.7, y: 40 }}\n        animate={{ opacity: 1, scale: 1, y: 0 }}\n        transition={{ type: \"spring\", stiffness: 300, damping: 24 }}\n        style={{ position: \"relative\", zIndex: 10, width: \"100%\", maxWidth: 380, borderRadius: 28, background: \"#181230\", border: \"1px solid rgba(107,53,232,0.3)\", overflow: \"hidden\", textAlign: \"center\", padding: \"40px 32px 32px\" }}>\n\n        {/* Glow */}\n        <div style={{ position: \"absolute\", top: -40, left: \"50%\", transform: \"translateX(-50%)\", width: 200, height: 200, borderRadius: \"50%\", background: \"radial-gradient(circle, rgba(107,53,232,0.5), transparent 70%)\", filter: \"blur(30px)\", pointerEvents: \"none\" }} />\n\n        <button onClick={onDismiss} style={{ position: \"absolute\", top: 16, right: 16, color: \"rgba(255,255,255,0.3)\", background: \"none\", border: \"none\", cursor: \"pointer\" }}>\n          <X size={18} />\n        </button>\n\n        {/* Icon */}\n        <motion.div\n          animate={{ rotate: [0, -10, 10, -5, 5, 0], scale: [1, 1.1, 1] }}\n          transition={{ duration: 1, delay: 0.3 }}\n          style={{ fontSize: 56, marginBottom: 16, display: \"block\" }}>\n          🔥\n        </motion.div>\n\n        <motion.h1\n          initial={{ opacity: 0, y: 20 }}\n          animate={{ opacity: 1, y: 0 }}\n          transition={{ delay: 0.2 }}\n          style={{ fontSize: 28, fontWeight: 900, color: \"#fff\", letterSpacing: \"-1.5px\", marginBottom: 8 }}>\n          FIRST SALE!\n        </motion.h1>\n\n        <motion.div\n          initial={{ opacity: 0, y: 16 }}\n          animate={{ opacity: 1, y: 0 }}\n          transition={{ delay: 0.35 }}\n          style={{ marginBottom: 24 }}>\n          {orderAmount && (\n            <p style={{ fontSize: 32, fontWeight: 900, color: \"#10B981\", letterSpacing: \"-1px\", marginBottom: 4 }}>\n              {fmt(orderAmount)}\n            </p>\n          )}\n          <p style={{ fontSize: 14, color: \"rgba(255,255,255,0.55)\", lineHeight: 1.6 }}>\n            {customerName ? `${customerName} just bought from your store.` : \"Someone just bought from your store.\"}\n            {\" \"}This is your first step to financial freedom.\n          </p>\n        </motion.div>\n\n        <motion.div\n          initial={{ opacity: 0, y: 12 }}\n          animate={{ opacity: 1, y: 0 }}\n          transition={{ delay: 0.5 }}\n          style={{ display: \"flex\", gap: 10 }}>\n          <Link href=\"/dashboard/orders\" style={{ flex: 1, textDecoration: \"none\" }}>\n            <button style={{ width: \"100%\", padding: \"12px\", borderRadius: 14, background: \"linear-gradient(135deg,#6B35E8,#3D1C8A)\", border: \"none\", color: \"#fff\", fontSize: 14, fontWeight: 700, cursor: \"pointer\", display: \"flex\", alignItems: \"center\", justifyContent: \"center\", gap: 6, boxShadow: \"0 8px 24px rgba(107,53,232,0.4)\" }}>\n              View Order <ArrowRight size={14} />\n            </button>\n          </Link>\n          <button\n            onClick={() => {\n              navigator.share?.({ title: \"I just made my first sale on DropOS! 🔥\", text: \"I launched my store and got my first sale in days. You should try DropOS!\", url: \"https://droposhq.com\" })\n                .catch(() => navigator.clipboard.writeText(\"I just made my first sale on DropOS! 🔥 Try it: https://droposhq.com\"));\n              toast?.success?.(\"Copied to share!\");\n            }}\n            style={{ padding: \"12px 14px\", borderRadius: 14, border: \"1px solid rgba(255,255,255,0.12)\", background: \"rgba(255,255,255,0.05)\", color: \"rgba(255,255,255,0.7)\", cursor: \"pointer\" }}>\n            <Share2 size={16} />\n          </button>\n        </motion.div>\n\n        <motion.p\n          initial={{ opacity: 0 }}\n          animate={{ opacity: 1 }}\n          transition={{ delay: 0.8 }}\n          style={{ fontSize: 11, color: \"rgba(255,255,255,0.2)\", marginTop: 16 }}>\n          KIRO is already working on getting you the next one\n        </motion.p>\n      </motion.div>\n    </div>\n  );\n}\n","frontend/src/components/store/SocialProof.tsx":"\"use client\";\nimport { useState, useEffect } from \"react\";\nimport { motion, AnimatePresence } from \"framer-motion\";\nimport { ShoppingBag, Eye, Zap } from \"lucide-react\";\n\nconst NIGERIAN_FIRST_NAMES = [\"Amaka\",\"Tunde\",\"Chisom\",\"Aisha\",\"Emeka\",\"Fatima\",\"Bayo\",\"Ngozi\",\"Seun\",\"Zara\",\"Kemi\",\"Chidi\",\"Yemi\",\"Adaeze\",\"Ibrahim\",\"Blessing\",\"Femi\",\"Ifeoma\",\"Kunle\",\"Sade\"];\nconst NIGERIAN_CITIES = [\"Lagos\",\"Abuja\",\"Port Harcourt\",\"Ibadan\",\"Kano\",\"Enugu\",\"Benin City\",\"Kaduna\",\"Aba\",\"Onitsha\",\"Jos\",\"Ilorin\",\"Warri\",\"Calabar\",\"Uyo\"];\n\nfunction randomName() { return NIGERIAN_FIRST_NAMES[Math.floor(Math.random() * NIGERIAN_FIRST_NAMES.length)]; }\nfunction randomCity() { return NIGERIAN_CITIES[Math.floor(Math.random() * NIGERIAN_CITIES.length)]; }\n\ninterface SocialProofToast {\n  id:     number;\n  name:   string;\n  city:   string;\n  action: \"bought\" | \"viewing\";\n  time:   number;\n}\n\ninterface Props {\n  productName?: string;\n  viewerCount?: number;\n  brand?:       string;\n}\n\nexport function SocialProofPopup({ productName, viewerCount = 0, brand = \"#6B35E8\" }: Props) {\n  const [toasts, setToasts] = useState<SocialProofToast[]>([]);\n\n  useEffect(() => {\n    // Show a purchase notification every 15-45 seconds\n    const schedule = () => {\n      const delay = 15000 + Math.random() * 30000;\n      return setTimeout(() => {\n        const id = Date.now();\n        setToasts(prev => [...prev.slice(-1), {\n          id, name: randomName(), city: randomCity(), action: \"bought\", time: Math.floor(Math.random() * 12) + 1,\n        }]);\n        setTimeout(() => setToasts(p => p.filter(t => t.id !== id)), 5000);\n        schedule();\n      }, delay);\n    };\n\n    // First one after 5 seconds\n    const first = setTimeout(() => {\n      const id = Date.now();\n      setToasts([{ id, name: randomName(), city: randomCity(), action: \"bought\", time: 3 }]);\n      setTimeout(() => setToasts([]), 5000);\n    }, 5000);\n\n    const recurring = schedule();\n    return () => { clearTimeout(first); clearTimeout(recurring); };\n  }, []);\n\n  return (\n    <>\n      {/* Live viewers */}\n      {viewerCount > 1 && (\n        <div style={{ display: \"inline-flex\", alignItems: \"center\", gap: 5, padding: \"4px 10px\", borderRadius: 99, background: \"rgba(239,68,68,0.1)\", border: \"1px solid rgba(239,68,68,0.2)\", marginBottom: 8 }}>\n          <div style={{ width: 6, height: 6, borderRadius: \"50%\", background: \"#EF4444\", animation: \"pulse 1.5s ease infinite\" }} />\n          <span style={{ fontSize: 11, fontWeight: 600, color: \"#EF4444\" }}>{viewerCount} people viewing this now</span>\n        </div>\n      )}\n\n      {/* Toast popups */}\n      <div style={{ position: \"fixed\", bottom: 80, left: 12, zIndex: 9998, maxWidth: 280 }}>\n        <AnimatePresence>\n          {toasts.map(toast => (\n            <motion.div key={toast.id}\n              initial={{ opacity: 0, x: -20, y: 8 }}\n              animate={{ opacity: 1, x: 0, y: 0 }}\n              exit={{ opacity: 0, x: -20 }}\n              transition={{ type: \"spring\", stiffness: 400, damping: 28 }}\n              style={{ display: \"flex\", alignItems: \"center\", gap: 10, padding: \"10px 14px\", borderRadius: 12, background: \"#fff\", boxShadow: \"0 4px 24px rgba(0,0,0,0.15)\", marginBottom: 8 }}>\n              <div style={{ width: 32, height: 32, borderRadius: 10, background: `${brand}15`, display: \"flex\", alignItems: \"center\", justifyContent: \"center\", flexShrink: 0 }}>\n                <ShoppingBag size={15} style={{ color: brand }} />\n              </div>\n              <div>\n                <p style={{ fontSize: 12, fontWeight: 700, color: \"#111827\" }}>{toast.name} from {toast.city}</p>\n                <p style={{ fontSize: 11, color: \"#6b7280\" }}>purchased {toast.time < 60 ? `${toast.time} min ago` : \"recently\"}</p>\n              </div>\n            </motion.div>\n          ))}\n        </AnimatePresence>\n      </div>\n    </>\n  );\n}\n\nexport function StockUrgency({ inventory, threshold = 5 }: { inventory: number; threshold?: number }) {\n  if (inventory <= 0 || inventory > threshold) return null;\n\n  return (\n    <motion.div\n      initial={{ opacity: 0, scale: 0.95 }}\n      animate={{ opacity: 1, scale: 1 }}\n      style={{ display: \"inline-flex\", alignItems: \"center\", gap: 6, padding: \"5px 12px\", borderRadius: 20, background: inventory <= 2 ? \"rgba(239,68,68,0.1)\" : \"rgba(245,158,11,0.1)\", border: `1px solid ${inventory <= 2 ? \"rgba(239,68,68,0.3)\" : \"rgba(245,158,11,0.3)\"}` }}>\n      <motion.div\n        animate={{ scale: [1, 1.3, 1] }}\n        transition={{ duration: 1.5, repeat: Infinity }}\n        style={{ width: 6, height: 6, borderRadius: \"50%\", background: inventory <= 2 ? \"#EF4444\" : \"#F59E0B\" }}\n      />\n      <span style={{ fontSize: 12, fontWeight: 700, color: inventory <= 2 ? \"#DC2626\" : \"#D97706\" }}>\n        Only {inventory} left in stock\n      </span>\n    </motion.div>\n  );\n}\n\nexport function WhatsAppButton({ storeName, productName, productUrl, brand = \"#25D366\" }: { storeName: string; productName?: string; productUrl?: string; brand?: string }) {\n  const message = productName\n    ? `Hi! I'm interested in ${productName} from ${storeName}. Can you help me order?`\n    : `Hi! I'm interested in shopping at ${storeName}.`;\n\n  const waUrl = `https://wa.me/?text=${encodeURIComponent(message + (productUrl ? \" \" + productUrl : \"\"))}`;\n\n  return (\n    <a href={waUrl} target=\"_blank\" rel=\"noopener noreferrer\" style={{ textDecoration: \"none\" }}>\n      <motion.button\n        whileTap={{ scale: 0.96 }}\n        style={{ display: \"flex\", alignItems: \"center\", gap: 8, padding: \"10px 18px\", borderRadius: 12, background: \"#25D366\", border: \"none\", color: \"#fff\", fontSize: 13, fontWeight: 700, cursor: \"pointer\", boxShadow: \"0 4px 14px rgba(37,211,102,0.35)\" }}>\n        <svg width=\"16\" height=\"16\" viewBox=\"0 0 24 24\" fill=\"currentColor\">\n          <path d=\"M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.890-5.335 11.893-11.893A11.821 11.821 0 0020.885 3.49\"/>\n        </svg>\n        Order on WhatsApp\n      </motion.button>\n    </a>\n  );\n}\n","frontend/src/app/store/[slug]/checkout/page.tsx":"\"use client\";\n\nimport { useState, useEffect } from \"react\";\nimport { useParams, useRouter } from \"next/navigation\";\nimport { useQuery, useMutation } from \"@tanstack/react-query\";\nimport { api } from \"../../../../lib/api\";\nimport { publicApi } from \"../../../../lib/api\";\nimport { useCartStore } from \"../../../../store/cart.store\";\nimport { useCurrencyStore } from \"../../../../store/currency.store\";\nimport Link from \"next/link\";\nimport { useForm } from \"react-hook-form\";\nimport { zodResolver } from \"@hookform/resolvers/zod\";\nimport { z } from \"zod\";\nimport {\n  ArrowLeft, Package, ShieldCheck, Lock, CreditCard,\n  Loader2, ChevronDown, ChevronUp, Tag, CheckCircle,\n  Truck, Zap, X, Globe, ChevronRight,\n} from \"lucide-react\";\nimport toast from \"react-hot-toast\";\n\n// ── Schema ────────────────────────────────────────────────────────────────────\nconst schema = z.object({\n  name:       z.string().min(2, \"Name is required\"),\n  email:      z.string().email(\"Valid email required\"),\n  phone:      z.string().min(7, \"Phone is required\"),\n  address:    z.string().min(5, \"Address is required\"),\n  city:       z.string().min(2, \"City is required\"),\n  state:      z.string().min(2, \"State / province is required\"),\n  country:    z.string().min(2, \"Country is required\"),\n  postalCode: z.string().optional(),\n  notes:      z.string().optional(),\n});\ntype CheckoutForm = z.infer<typeof schema>;\n\n// ── Shipping options ─────────────────────────────────────────────────────────\n// Shipping options built from store's zone config or sensible NG defaults\nconst getShippingOptions = (store: any) => {\n  if (store?.shippingZones?.length) {\n    return store.shippingZones.map((z: any) => ({\n      id:    z.id,\n      label: z.name === \"express\" ? \"Express Delivery\" : z.name === \"cod\" ? \"Pay on Delivery\" : \"Standard Delivery\",\n      desc:  z.estimatedDays ? `${z.estimatedDays} business days` : \"3-7 business days\",\n      price: z.rate || 0,\n      icon:  z.name === \"express\" ? Zap : z.name === \"cod\" ? Package : Truck,\n      cod:   z.name === \"cod\" || z.cashOnDelivery,\n    }));\n  }\n  // Nigerian defaults\n  return [\n    { id: \"standard\", label: \"Standard Delivery\",  desc: \"3-7 business days\",  price: 2500, icon: Truck,   cod: false },\n    { id: \"express\",  label: \"Express Delivery\",   desc: \"1-2 business days\",  price: 5000, icon: Zap,     cod: false },\n    { id: \"cod\",      label: \"Pay on Delivery\",    desc: \"3-7 business days\",  price: 2500, icon: Package, cod: true  },\n  ];\n};\nconst SHIPPING_OPTIONS_PLACEHOLDER = [\n  { id: \"standard\", label: \"Standard Delivery\",  desc: \"3-7 business days\",  price: 2500, icon: Truck,   cod: false },\n  { id: \"express\",  label: \"Express Delivery\",   desc: \"1-2 business days\",  price: 5000, icon: Zap,     cod: false },\n  { id: \"cod\",      label: \"Pay on Delivery\",    desc: \"3-7 business days\",  price: 2500, icon: Package, cod: true  },\n];\n\n// ── Trust badges ─────────────────────────────────────────────────────────────\nconst TRUST = [\n  { icon: \"🔒\", label: \"SSL Encrypted\" },\n  { icon: \"✅\", label: \"Secure Checkout\" },\n  { icon: \"🔄\", label: \"Easy Returns\" },\n  { icon: \"🚚\", label: \"Fast Delivery\" },\n];\n\n// ── Step indicator ────────────────────────────────────────────────────────────\nfunction StepBadge({ n, label, brand }: { n: number; label: string; brand: string }) {\n  return (\n    <h2 className=\"font-black text-lg text-slate-900 mb-5 flex items-center gap-2.5\">\n      <span className=\"w-7 h-7 rounded-lg flex items-center justify-center text-[var(--text-primary)] text-xs font-black flex-shrink-0\"\n        style={{ background: `linear-gradient(135deg,${brand},${brand}bb)` }}>\n        {n}\n      </span>\n      {label}\n    </h2>\n  );\n}\n\n// ── Input style ───────────────────────────────────────────────────────────────\nconst inp = \"w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm text-slate-900 placeholder-slate-400 outline-none focus:border-violet-500 focus:ring-2 focus:ring-violet-100 transition-all\";\nconst lbl = \"block text-xs font-semibold text-slate-600 mb-1.5\";\n\n// ── Main ──────────────────────────────────────────────────────────────────────\nexport default function CheckoutPage() {\n  const { slug }   = useParams<{ slug: string }>();\n  const router     = useRouter();\n  const { items, total, clearCart, setCaptured, setPendingOrder } = useCartStore();\n\n  const [summaryOpen,   setSummaryOpen]   = useState(false);\n  const [couponCode,    setCouponCode]    = useState(\"\");\n  const [couponApplied, setCouponApplied] = useState<{ code: string; discount: number; label: string } | null>(null);\n  const [couponError,   setCouponError]   = useState(\"\");\n  const [couponLoading, setCouponLoading] = useState(false);\n  const [shipping,      setShipping]      = useState(SHIPPING_OPTIONS_PLACEHOLDER[0]);\n  const [paymentMethod, setPaymentMethod] = useState<\"paystack\" | \"cod\">(\"paystack\");\n  const [step,          setStep]          = useState<1|2>(1); // 1=info, 2=review\n\n  const { data: store } = useQuery({\n    queryKey: [\"public-store\", slug],\n    queryFn:  () => publicApi.get(`/stores/public/${slug}`).then(r => r.data.data),\n  });\n\n  const shippingOptions = store ? getShippingOptions(store) : SHIPPING_OPTIONS_PLACEHOLDER;\n  useEffect(() => { if (store) setShipping(shippingOptions[0]); }, [store?.id]);\n  const brand    = store?.primaryColor || \"#7c3aed\";\n  const currency = store?.currency     || \"USD\";\n  const { format: fmtCurrency, displayCurrency, setBaseCurrency } = useCurrencyStore();\n  useEffect(() => { if (store?.currency) setBaseCurrency(store.currency); }, [store]);\n  const fmt = (n: number) => fmtCurrency(n, currency);\n\n  // Totals\n  const taxRate    = (store?.taxRate || 0) / 100;\n  const subtotal   = total();\n  const freeShip   = subtotal >= (store?.freeShippingThreshold || 50);\n  const shipCost   = freeShip ? 0 : shipping.price;\n  const tax        = subtotal * taxRate;\n  const discount   = couponApplied?.discount ?? 0;\n  const grandTotal = Math.max(0, subtotal + shipCost + tax - discount);\n\n  const { register, handleSubmit, getValues, formState: { errors } } = useForm<CheckoutForm>({\n    resolver: zodResolver(schema),\n  });\n\n  // Redirect if cart empty\n  useEffect(() => {\n    if (items.length === 0) router.replace(`/store/${slug}`);\n  }, [items.length, slug, router]);\n\n  // ── Coupon validation ─────────────────────────────────────────────────────\n  const applyCoupon = async () => {\n    if (!couponCode.trim()) return;\n    setCouponLoading(true);\n    setCouponError(\"\");\n    try {\n      const res = await publicApi.post(\"/coupons/validate\", {\n        code:       couponCode.trim().toUpperCase(),\n        storeId:    store?.id,\n        orderTotal: subtotal,\n      });\n      const { coupon, discount: d } = res.data.data;\n      setCouponApplied({ code: coupon.code, discount: d, label: coupon.type === \"PERCENTAGE\" ? `${coupon.value}% off` : `$${coupon.value} off` });\n      toast.success(`Coupon applied: ${coupon.type === \"PERCENTAGE\" ? coupon.value + \"% off\" : \"$\" + coupon.value + \" off\"}`);\n    } catch (e: any) {\n      setCouponError(e.response?.data?.message || \"Invalid coupon\");\n    } finally {\n      setCouponLoading(false);\n    }\n  };\n\n  // ── Also check automatic discounts ───────────────────────────────────────\n  const { data: autoDiscounts } = useQuery({\n    queryKey: [\"auto-discounts\", store?.id, subtotal],\n    queryFn:  () => publicApi.post(\"/discounts/evaluate\", {\n      storeId:    store?.id,\n      cartItems:  items.map(i => ({ productId: i.productId, qty: i.quantity, price: i.price })),\n      subtotal,\n    }).then(r => r.data.data),\n    enabled: !!store?.id && subtotal > 0,\n  });\n\n  const autoDiscountTotal = autoDiscounts?.totalDiscount || 0;\n  const autoFreeShipping  = autoDiscounts?.freeShipping || false;\n  const effectiveShipCost = autoFreeShipping || freeShip ? 0 : shipCost;\n  const effectiveTotal    = Math.max(0, subtotal + effectiveShipCost + tax - discount - autoDiscountTotal);\n\n  // ── Place order ───────────────────────────────────────────────────────────\n  const checkoutMut = useMutation({\n    mutationFn: async (d: CheckoutForm) => {\n      const orderRes = await publicApi.post(\"/orders\", {\n        storeId:       store.id,\n        customerName:  d.name,\n        customerEmail: d.email,\n        customerPhone: d.phone,\n        shippingAddress: {\n          address:    d.address,\n          city:       d.city,\n          state:      d.state,\n          country:    d.country,\n          postalCode: d.postalCode,\n        },\n        shippingCost:   effectiveShipCost,\n        taxAmount:      tax,\n        discountAmount: discount + autoDiscountTotal,\n        couponCode:     couponApplied?.code,\n        shippingMethod: shipping.id,\n        notes:          d.notes,\n        items:          items.map(i => ({\n          productId: i.productId, variantId: i.variantId,\n          quantity:  i.quantity,  price: i.price, name: i.name,\n        })),\n        subtotal,\n        taxAmount:      tax,\n        shippingCost:   effectiveShipCost,\n        total:          effectiveTotal,\n        discountAmount: discount + autoDiscountTotal,\n      });\n      const order = orderRes.data.data;\n\n      // Init payment\n      const payRes = await publicApi.post(\"/payments/initialize\", {\n        orderId: order.id,\n        country: d.country,\n      });\n\n      return { order, payment: payRes.data.data };\n    },\n    onSuccess: ({ order, payment }) => {\n      // Stripe: don't clear cart yet - user may abandon the Stripe page\n      if (payment?.clientSecret) {\n        router.push(`/store/${slug}/payment?clientSecret=${payment.clientSecret}&orderId=${order.id}`);\n        return;\n      }\n      // External gateways (Paystack / Flutterwave): store orderId before leaving the app\n      // so the callback page can pass the real UUID to /payments/verify\n      if (payment?.authorizationUrl || payment?.paymentLink) {\n        setPendingOrder(order.id, slug);\n        clearCart();\n        window.location.href = payment.authorizationUrl || payment.paymentLink;\n        return;\n      }\n      // Cash on delivery / manual payment\n      clearCart();\n      router.push(`/store/${slug}/payment/callback?orderId=${order.id}&manual=true`);\n    },\n    onError: (e: any) => toast.error(e.response?.data?.message || \"Something went wrong\"),\n  });\n\n  if (items.length === 0) return null;\n\n  const showConversionNote = displayCurrency !== currency;\n\n  return (\n    <div className=\"min-h-screen bg-slate-50\">\n      {/* ── Header ── */}\n      <header className=\"bg-white border-b border-slate-200 sticky top-0 z-20 shadow-sm\">\n        <div className=\"max-w-5xl mx-auto px-4 sm:px-6 h-16 flex items-center justify-between\">\n          <Link href={`/store/${slug}`}\n            className=\"flex items-center gap-2 text-sm font-semibold text-slate-600 hover:text-slate-900 transition-colors\">\n            <ArrowLeft size={16} /> Continue shopping\n          </Link>\n          <div className=\"flex items-center gap-2\">\n            {store?.logo ? (\n              <img src={store.logo} alt={store.name} className=\"h-8 w-auto\" />\n            ) : (\n              <span className=\"font-black text-lg text-slate-900\">{store?.name}</span>\n            )}\n          </div>\n          <div className=\"flex items-center gap-1.5 text-xs text-slate-400\">\n            <Lock size={12} /> Secure Checkout\n          </div>\n        </div>\n      </header>\n\n      {/* ── Progress bar (mobile) ── */}\n      <div className=\"bg-white border-b border-slate-100 px-4 py-2 sm:hidden\">\n        <div className=\"flex items-center gap-2\">\n          {[{n:1,l:\"Information\"},{n:2,l:\"Review & Pay\"}].map(({n,l}) => (\n            <div key={n} className=\"flex items-center gap-1.5 flex-1\">\n              <span className=\"w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-black text-[var(--text-primary)] flex-shrink-0\"\n                style={{ background: step >= n ? brand : \"#CBD5E1\" }}>\n                {step > n ? \"✓\" : n}\n              </span>\n              <span className=\"text-xs font-semibold truncate\"\n                style={{ color: step >= n ? \"var(--slate-900, #0F172A)\" : \"#94A3B8\" }}>\n                {l}\n              </span>\n              {n < 2 && <ChevronRight size={12} className=\"text-slate-300 flex-shrink-0\" />}\n            </div>\n          ))}\n        </div>\n      </div>\n\n      <div className=\"max-w-5xl mx-auto px-4 sm:px-6 py-8\">\n        <div className=\"grid grid-cols-1 lg:grid-cols-5 gap-8\">\n\n          {/* ── LEFT: Form ── */}\n          <div className=\"lg:col-span-3 space-y-5\">\n            <form onSubmit={handleSubmit(d => checkoutMut.mutate(d))} className=\"space-y-5\">\n\n              {/* Contact */}\n              <div className=\"bg-white rounded-2xl border border-slate-200 p-6 shadow-sm\">\n                <StepBadge n={1} label=\"Contact Information\" brand={brand} />\n                <div className=\"grid grid-cols-1 sm:grid-cols-2 gap-4\">\n                  <div className=\"sm:col-span-2\">\n                    <label className={lbl}>Full Name</label>\n                    <input {...register(\"name\")} placeholder=\"John Doe\" className={inp} />\n                    {errors.name && <p className=\"text-xs text-red-500 mt-1\">{errors.name.message}</p>}\n                  </div>\n                  <div>\n                    <label className={lbl}>Email address</label>\n                    <input {...register(\"email\")}\n                      onBlur={e => { if (e.target.value.includes(\"@\")) setCaptured(e.target.value, getValues(\"name\")); }}\n                      type=\"email\" placeholder=\"john@email.com\" className={inp} />\n                    {errors.email && <p className=\"text-xs text-red-500 mt-1\">{errors.email.message}</p>}\n                  </div>\n                  <div>\n                    <label className={lbl}>Phone</label>\n                    <input {...register(\"phone\")} type=\"tel\" placeholder=\"+1 234 567 8900\" className={inp} />\n                    {errors.phone && <p className=\"text-xs text-red-500 mt-1\">{errors.phone.message}</p>}\n                  </div>\n                </div>\n              </div>\n\n              {/* Shipping address */}\n              <div className=\"bg-white rounded-2xl border border-slate-200 p-6 shadow-sm\">\n                <StepBadge n={2} label=\"Shipping Address\" brand={brand} />\n                <div className=\"grid grid-cols-1 sm:grid-cols-2 gap-4\">\n                  <div className=\"sm:col-span-2\">\n                    <label className={lbl}>Street address</label>\n                    <input {...register(\"address\")} placeholder=\"123 Main Street, Apt 4B\" className={inp} />\n                    {errors.address && <p className=\"text-xs text-red-500 mt-1\">{errors.address.message}</p>}\n                  </div>\n                  <div>\n                    <label className={lbl}>City</label>\n                    <input {...register(\"city\")} placeholder=\"New York\" className={inp} />\n                    {errors.city && <p className=\"text-xs text-red-500 mt-1\">{errors.city.message}</p>}\n                  </div>\n                  <div>\n                    <label className={lbl}>State / Province</label>\n                    <input {...register(\"state\")} placeholder=\"NY\" className={inp} />\n                    {errors.state && <p className=\"text-xs text-red-500 mt-1\">{errors.state.message}</p>}\n                  </div>\n                  <div>\n                    <label className={lbl}>Country</label>\n                    <input {...register(\"country\")} placeholder=\"United States\" className={inp} />\n                    {errors.country && <p className=\"text-xs text-red-500 mt-1\">{errors.country.message}</p>}\n                  </div>\n                  <div>\n                    <label className={lbl}>Postal / ZIP code</label>\n                    <input {...register(\"postalCode\")} placeholder=\"10001\" className={inp} />\n                  </div>\n                </div>\n              </div>\n\n              {/* Shipping method */}\n              <div className=\"bg-white rounded-2xl border border-slate-200 p-6 shadow-sm\">\n                <StepBadge n={3} label=\"Shipping Method\" brand={brand} />\n                <div className=\"space-y-2\">\n                  {shippingOptions.map(opt => {\n                    const isActive = shipping.id === opt.id;\n                    const isFreeByStore = freeShip && opt.id === \"free\";\n                    return (\n                      <button key={opt.id} type=\"button\" onClick={() => setShipping(opt)}\n                        className=\"w-full flex items-center justify-between p-4 rounded-xl border-2 transition-all text-left\"\n                        style={{\n                          borderColor: isActive ? brand : \"#E2E8F0\",\n                          background:  isActive ? brand + \"06\" : \"#F8FAFC\",\n                        }}>\n                        <div className=\"flex items-center gap-3\">\n                          <div className=\"w-8 h-8 rounded-lg flex items-center justify-center\"\n                            style={{ background: isActive ? brand + \"15\" : \"#F1F5F9\" }}>\n                            <opt.icon size={15} style={{ color: isActive ? brand : \"#94A3B8\" }} />\n                          </div>\n                          <div>\n                            <div className=\"text-sm font-bold text-slate-900\">{opt.label}</div>\n                            <div className=\"text-xs text-slate-500\">{opt.desc}</div>\n                          </div>\n                        </div>\n                        <div className=\"flex items-center gap-3\">\n                          <span className=\"text-sm font-black\"\n                            style={{ color: (opt.price === 0 || isFreeByStore || autoFreeShipping) ? \"#10B981\" : \"#0F172A\" }}>\n                            {opt.price === 0 || isFreeByStore || autoFreeShipping ? \"FREE\" : fmt(opt.price)}\n                          </span>\n                          <div className=\"w-4 h-4 rounded-full border-2 flex items-center justify-center\"\n                            style={{ borderColor: isActive ? brand : \"#CBD5E1\" }}>\n                            {isActive && <div className=\"w-2 h-2 rounded-full\" style={{ background: brand }} />}\n                          </div>\n                        </div>\n                      </button>\n                    );\n                  })}\n                </div>\n                {(freeShip || autoFreeShipping) && (\n                  <div className=\"mt-3 flex items-center gap-2 text-xs font-semibold text-emerald-600\">\n                    <CheckCircle size={13} /> You qualify for free shipping!\n                  </div>\n                )}\n              </div>\n\n              {/* Notes */}\n              <div className=\"bg-white rounded-2xl border border-slate-200 p-6 shadow-sm\">\n                <StepBadge n={4} label={<>Order Notes <span className=\"text-sm text-slate-400 font-normal\">(Optional)</span></> as any} brand={brand} />\n                <textarea {...register(\"notes\")} rows={2}\n                  placeholder=\"Special delivery instructions, gift message, etc.\"\n                  className={`${inp} resize-none`} />\n              </div>\n\n              {/* Payment notice */}\n              <div className=\"bg-white rounded-2xl border border-slate-200 p-6 shadow-sm\">\n                <StepBadge n={5} label=\"Payment\" brand={brand} />\n                <div className=\"flex items-start gap-3 p-4 rounded-xl bg-slate-50 border border-slate-200\">\n                  <CreditCard size={18} className=\"text-slate-400 mt-0.5 flex-shrink-0\" />\n                  <div>\n                    <p className=\"text-sm font-bold text-slate-700\">Secure Payment</p>\n                    <p className=\"text-xs text-slate-500 mt-0.5\">\n                      After placing your order you'll complete payment on our secure payment page.\n                      We accept Visa, Mastercard, Amex, Apple Pay, and Google Pay.\n                    </p>\n                    <div className=\"flex items-center gap-2 mt-3\">\n                      {[\"VISA\",\"MC\",\"AMEX\",\"🍎 Pay\",\"G Pay\"].map(c => (\n                        <span key={c} className=\"px-2 py-1 rounded-md text-[10px] font-bold bg-white border border-slate-200 text-slate-600\">{c}</span>\n                      ))}\n                    </div>\n                  </div>\n                </div>\n              </div>\n\n              {/* Submit */}\n              <button type=\"submit\" disabled={checkoutMut.isPending}\n                className=\"w-full py-4 rounded-2xl text-[var(--text-primary)] font-black text-base shadow-xl flex items-center justify-center gap-3 transition-all hover:opacity-90 hover:-translate-y-0.5 disabled:opacity-60 disabled:cursor-not-allowed disabled:translate-y-0\"\n                style={{ background: `linear-gradient(135deg,${brand},${brand}cc)`, boxShadow: `0 12px 32px ${brand}35` }}>\n                {checkoutMut.isPending\n                  ? <><Loader2 size={18} className=\"animate-spin\" /> Processing…</>\n                  : <><Lock size={16} /> Place Order · {fmt(effectiveTotal)}</>}\n              </button>\n\n              <div className=\"flex items-center justify-center gap-2 text-xs text-slate-400\">\n                <ShieldCheck size={13} /> Your information is encrypted and secure\n              </div>\n            </form>\n          </div>\n\n          {/* ── RIGHT: Order Summary ── */}\n          <div className=\"lg:col-span-2\">\n            <div className=\"bg-white rounded-2xl border border-slate-200 shadow-sm sticky top-24\">\n\n              {/* Mobile toggle */}\n              <button className=\"lg:hidden w-full flex items-center justify-between p-5 font-black text-slate-900\"\n                onClick={() => setSummaryOpen(!summaryOpen)}>\n                <span>Order Summary ({items.length} item{items.length !== 1 ? \"s\" : \"\"})</span>\n                {summaryOpen ? <ChevronUp size={16} /> : <ChevronDown size={16} />}\n              </button>\n\n              <div className={`lg:block ${summaryOpen ? \"block\" : \"hidden\"}`}>\n                {/* Header */}\n                <div className=\"p-5 hidden lg:block border-b border-slate-100\">\n                  <h3 className=\"font-black text-slate-900\">Order Summary</h3>\n                  <p className=\"text-sm text-slate-400 mt-0.5\">\n                    {items.length} item{items.length !== 1 ? \"s\" : \"\"}\n                  </p>\n                </div>\n\n                {/* Items */}\n                <div className=\"p-4 space-y-3 max-h-64 overflow-y-auto\">\n                  {items.map(item => (\n                    <div key={`${item.productId}-${item.variantId}`} className=\"flex gap-3\">\n                      <div className=\"relative flex-shrink-0\">\n                        <div className=\"w-13 h-13 w-[52px] h-[52px] rounded-xl overflow-hidden bg-slate-100\">\n                          {item.image\n                            ? <img src={item.image} alt={item.name} className=\"w-full h-full object-cover\" />\n                            : <div className=\"w-full h-full flex items-center justify-center\"><Package size={14} className=\"text-slate-400\" /></div>}\n                        </div>\n                        <span className=\"absolute -top-1.5 -right-1.5 w-5 h-5 rounded-full bg-slate-700 text-[var(--text-primary)] text-[10px] font-black flex items-center justify-center\">\n                          {item.quantity}\n                        </span>\n                      </div>\n                      <div className=\"flex-1 min-w-0\">\n                        <p className=\"text-sm font-semibold text-slate-800 line-clamp-2 leading-snug\">{item.name}</p>\n                        {item.variantLabel && <p className=\"text-xs text-slate-400 mt-0.5\">{item.variantLabel}</p>}\n                      </div>\n                      <span className=\"text-sm font-black text-slate-900 flex-shrink-0\">\n                        {fmt(item.price * item.quantity)}\n                      </span>\n                    </div>\n                  ))}\n                </div>\n\n                {/* Coupon field */}\n                <div className=\"px-4 pb-4\">\n                  <div className=\"flex gap-2\">\n                    <div className=\"relative flex-1\">\n                      <Tag size={13} className=\"absolute left-3 top-1/2 -translate-y-1/2 text-slate-400\" />\n                      <input\n                        value={couponCode}\n                        onChange={e => { setCouponCode(e.target.value.toUpperCase()); setCouponError(\"\"); }}\n                        onKeyDown={e => e.key === \"Enter\" && (e.preventDefault(), applyCoupon())}\n                        placeholder=\"Coupon code\"\n                        disabled={!!couponApplied}\n                        className=\"w-full pl-9 pr-3 py-2.5 text-sm bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-violet-400 font-mono uppercase disabled:opacity-60\"\n                      />\n                    </div>\n                    {couponApplied ? (\n                      <button onClick={() => { setCouponApplied(null); setCouponCode(\"\"); }}\n                        className=\"px-3 py-2.5 rounded-xl text-xs font-bold bg-red-50 text-red-500 border border-red-200 hover:bg-red-100 transition-colors flex items-center gap-1\">\n                        <X size={12} /> Remove\n                      </button>\n                    ) : (\n                      <button onClick={applyCoupon} disabled={!couponCode || couponLoading}\n                        className=\"px-4 py-2.5 rounded-xl text-xs font-black text-[var(--text-primary)] disabled:opacity-50 transition-colors\"\n                        style={{ background: brand }}>\n                        {couponLoading ? <Loader2 size={12} className=\"animate-spin\" /> : \"Apply\"}\n                      </button>\n                    )}\n                  </div>\n                  {couponError && <p className=\"text-xs text-red-500 mt-1.5\">{couponError}</p>}\n                  {couponApplied && (\n                    <p className=\"text-xs text-emerald-600 mt-1.5 font-semibold\">\n                      ✓ {couponApplied.code} - {couponApplied.label} applied\n                    </p>\n                  )}\n                </div>\n\n                {/* Totals */}\n                <div className=\"px-5 pb-5 border-t border-slate-100 pt-4 space-y-2.5\">\n                  <div className=\"flex justify-between text-sm\">\n                    <span className=\"text-slate-500\">Subtotal</span>\n                    <span className=\"font-semibold text-slate-700\">{fmt(subtotal)}</span>\n                  </div>\n\n                  <div className=\"flex justify-between text-sm\">\n                    <span className=\"text-slate-500\">Shipping</span>\n                    <span className={`font-semibold ${effectiveShipCost === 0 ? \"text-emerald-600\" : \"text-slate-700\"}`}>\n                      {effectiveShipCost === 0 ? \"FREE 🎉\" : fmt(effectiveShipCost)}\n                    </span>\n                  </div>\n\n                  {tax > 0 && (\n                    <div className=\"flex justify-between text-sm\">\n                      <span className=\"text-slate-500\">Tax ({store?.taxRate}%)</span>\n                      <span className=\"font-semibold text-slate-700\">{fmt(tax)}</span>\n                    </div>\n                  )}\n\n                  {/* Auto discounts */}\n                  {autoDiscountTotal > 0 && (\n                    <div className=\"flex justify-between text-sm\">\n                      <span className=\"text-emerald-600 font-semibold\">\n                        {autoDiscounts?.autoDiscounts?.[0]?.discount?.name || \"Auto discount\"}\n                      </span>\n                      <span className=\"font-bold text-emerald-600\">−{fmt(autoDiscountTotal)}</span>\n                    </div>\n                  )}\n\n                  {/* Coupon discount */}\n                  {couponApplied && (\n                    <div className=\"flex justify-between text-sm\">\n                      <span className=\"text-emerald-600 font-semibold\">Coupon ({couponApplied.label})</span>\n                      <span className=\"font-bold text-emerald-600\">−{fmt(discount)}</span>\n                    </div>\n                  )}\n\n                  <div className=\"flex justify-between font-black text-base text-slate-900 border-t border-slate-200 pt-2.5\">\n                    <span>Total</span>\n                    <div className=\"text-right\">\n                      <span style={{ color: brand }}>{fmt(effectiveTotal)}</span>\n                      {showConversionNote && (\n                        <div className=\"text-xs text-slate-400 mt-0.5 font-normal\">\n                          Charged in {currency}\n                        </div>\n                      )}\n                    </div>\n                  </div>\n\n                  {subtotal < (store?.freeShippingThreshold || 50) && !autoFreeShipping && (\n                    <div className=\"mt-1 text-xs text-center text-slate-400\">\n                      Add {fmt((store?.freeShippingThreshold || 50) - subtotal)} more for free shipping\n                    </div>\n                  )}\n                </div>\n\n                {/* Trust badges */}\n                <div className=\"px-4 pb-4 grid grid-cols-2 gap-2\">\n                  {TRUST.map(({ icon, label }) => (\n                    <div key={label} className=\"flex items-center gap-1.5 text-xs text-slate-400\">\n                      <span>{icon}</span> {label}\n                    </div>\n                  ))}\n                </div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  );\n}"};
let n=0;
for(const [rel,content] of Object.entries(files)){
  const p=rel.replace(/\//g,path.sep);
  fs.mkdirSync(path.dirname(p),{recursive:true});
  fs.writeFileSync(p,content,'utf8');
  console.log('OK',rel.split('/').slice(-2).join('/'));
  n++;
}
console.log('Written:',n,'files');
try{
  execSync('git add .',{stdio:'inherit'});
  const st=execSync('git status --short',{encoding:'utf8'}).trim();
  if(st){
    execSync('git commit -m "feat: Phase 1 - KIRO real streaming + /kiro/smart-chat endpoint, PWA service worker, credit system, plan gates, setup checklist, first sale celebration, social proof popups, stock urgency, WhatsApp button, Pay on Delivery at checkout"',{stdio:'inherit'});
    execSync('git push origin main',{stdio:'inherit'});
    console.log('Pushed. Vercel deploying.');
  } else { console.log('Nothing new. Run: git push origin main'); }
}catch(e){console.log('Git:',e.message);}
